+/**
+ * Notification history service — business logic for logging and querying sent notifications.
+ *
+ * Provides:
+ * - `log()`: Persists a notification record to the repository.
+ * - `query()`: Filters notification history by recipient, type, channel, status, date range.
+ * - Convenience accessors: `getByRecipient()`, `getByType()`, `getByDateRange()`.
+ *
+ * Depends on:
+ * - NotificationLogRepository (data layer) for persistence
+ */
+
+import type { Notification } from '../models/notification.js';
+import type {
+  NotificationLog,
+  NotificationHistoryQuery,
+} from '../models/notification-log.js';
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextId++).padStart(4, '0')}`;
+}
+
+/** Reset the ID counter (for testing). */
+export function resetNotificationLogIdCounter(): void {
+  nextId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Log a sent notification. Converts a Notification record into a persisted NotificationLog.
+   */
+  log(notification: Notification): NotificationLog {
+    const entry: NotificationLog = {
+      id: generateLogId(),
+      recipient: notification.recipient,
+      channel: notification.channel,
+      type: notification.type,
+      subject: notification.subject,
+      body: notification.body,
+      status: notification.status,
+      sentAt: notification.sentAt,
+      error: notification.error,
+      metadata: notification.metadata,
+    };
+
+    this.repository.save(entry);
+    this.logger.info(
+      `Logged notification ${entry.id} [${entry.channel}] to ${entry.recipient}: ${entry.status}`,
+    );
+    return entry;
+  }
+
+  /**
+   * Query notification history with flexible filters.
+   * All filter fields are optional — omitted fields match everything.
+   */
+  query(filters: NotificationHistoryQuery): NotificationLog[] {
+    return this.repository.findAll((entry) => {
+      if (filters.recipient !== undefined && entry.recipient !== filters.recipient) {
+        return false;
+      }
+      if (filters.type !== undefined && entry.type !== filters.type) {
+        return false;
+      }
+      if (filters.channel !== undefined && entry.channel !== filters.channel) {
+        return false;
+      }
+      if (filters.status !== undefined && entry.status !== filters.status) {
+        return false;
+      }
+      if (filters.startDate !== undefined && entry.sentAt < filters.startDate) {
+        return false;
+      }
+      if (filters.endDate !== undefined && entry.sentAt > filters.endDate) {
+        return false;
+      }
+      return true;
+    });
+  }
+
+  /**
+   * Get all notification logs for a specific recipient.
+   */
+  getByRecipient(recipient: string): NotificationLog[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get all notification logs of a specific type.
+   */
+  getByType(type: NotificationLog['type']): NotificationLog[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get all notification logs within a date range (inclusive).
+   */
+  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
+    return this.repository.findByDateRange(startDate, endDate);
+  }
+
+  /**
+   * Get total count of logged notifications.
+   */
+  getCount(): number {
+    return this.repository.count();
+  }
+}

