 * capturing the recipient, channel, type, delivery status, and timestamp.
 * These records are persisted via the NotificationLogRepository for querying.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * Delivery status of a logged notification.
 */
export type DeliveryStatus = 'sent' | 'failed';

/**
 * A persisted record of a notification that was dispatched.
 */
export interface NotificationLog {
  id: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  body: string;
  status: DeliveryStatus;
  sentAt: Date;
  error?: string;
  metadata?: Record<string, unknown>;
}

/**
 * Filter criteria for querying notification history.
 */
export interface NotificationHistoryQuery {
  /** Filter by recipient (exact match). */
  recipient?: string;
  /** Filter by notification type. */
  type?: NotificationType;
  /** Filter by delivery channel. */
  channel?: NotificationChannel;
  /** Filter by delivery status. */
  status?: DeliveryStatus;
  /** Only include logs on or after this date. */
  startDate?: Date;
  /** Only include logs on or before this date. */
  endDate?: Date;
}

/**
 * Repository for notification log data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 * Serializes metadata as JSON for DB storage (same pattern as PreferencesRepository).
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    const log: NotificationLog = {
      id: record['id'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationLog['channel'],
      type: record['type'] as NotificationLog['type'],
      subject: record['subject'] as string,
      body: record['body'] as string,
      status: record['status'] as NotificationLog['status'],
      sentAt: new Date(record['sentAt'] as string),
    };

    if (record['error'] !== undefined) {
      log.error = record['error'] as string;
    }

    if (record['metadata'] !== undefined) {
      log.metadata = JSON.parse(record['metadata'] as string) as Record<string, unknown>;
    }

    return log;
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      subject: entity.subject,
      body: entity.body,
      status: entity.status,
      sentAt: entity.sentAt.toISOString(),
    };

    if (entity.error !== undefined) {
      record['error'] = entity.error;
    }

    if (entity.metadata !== undefined) {
      record['metadata'] = JSON.stringify(entity.metadata);
    }

    return record;
  }

  /**
   * Find all logs for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /**
   * Find all logs of a specific notification type.
   */
  findByType(type: NotificationLog['type']): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  /**
   * Find all logs within a date range (inclusive).
   */
  findByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.sentAt >= startDate && log.sentAt <= endDate,
    );
  }
}

/**
 * Notification history service — business logic for logging and querying sent notifications.
 *
 * Provides:
 * - `log()`: Persists a notification record to the repository.
 * - `query()`: Filters notification history by recipient, type, channel, status, date range.
 * - Convenience accessors: `getByRecipient()`, `getByType()`, `getByDateRange()`.
 *
 * Depends on:
 * - NotificationLogRepository (data layer) for persistence
 */

import type { Notification } from '../models/notification.js';
import type {
  NotificationLog,
  NotificationHistoryQuery,
} from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateLogId(): string {
  return `nlog-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetNotificationLogIdCounter(): void {
  nextId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a sent notification. Converts a Notification record into a persisted NotificationLog.
   */
  log(notification: Notification): NotificationLog {
    const entry: NotificationLog = {
      id: generateLogId(),
      recipient: notification.recipient,
      channel: notification.channel,
      type: notification.type,
      subject: notification.subject,
      body: notification.body,
      status: notification.status,
      sentAt: notification.sentAt,
      error: notification.error,
      metadata: notification.metadata,
    };

    this.repository.save(entry);
    this.logger.info(
      `Logged notification ${entry.id} [${entry.channel}] to ${entry.recipient}: ${entry.status}`,
    );
    return entry;
  }

  /**
   * Query notification history with flexible filters.
   * All filter fields are optional — omitted fields match everything.
   */
  query(filters: NotificationHistoryQuery): NotificationLog[] {
    return this.repository.findAll((entry) => {
      if (filters.recipient !== undefined && entry.recipient !== filters.recipient) {
        return false;
      }
      if (filters.type !== undefined && entry.type !== filters.type) {
        return false;
      }
      if (filters.channel !== undefined && entry.channel !== filters.channel) {
        return false;
      }
      if (filters.status !== undefined && entry.status !== filters.status) {
        return false;
      }
      if (filters.startDate !== undefined && entry.sentAt < filters.startDate) {
        return false;
      }
      if (filters.endDate !== undefined && entry.sentAt > filters.endDate) {
        return false;
      }
      return true;
    });
  }

  /**
   * Get all notification logs for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all notification logs of a specific type.
   */
  getByType(type: NotificationLog['type']): NotificationLog[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all notification logs within a date range (inclusive).
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  /**
   * Get total count of logged notifications.
   */
  getCount(): number {
    return this.repository.count();
  }
}

