import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed.',
    status: 'sent',
    sentAt: new Date('2026-01-15T10:00:00Z'),
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

function makeOrderCreatedEvent(overrides: Partial<OrderCreatedEvent> = {}): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetNotificationLogIdCounter();
  });

  describe('log', () => {
    it('should persist a notification log entry', () => {
      const notification = makeNotification();
      const entry = historyService.log(notification);

      expect(entry.id).toBe('nlog-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order_confirmation');
      expect(entry.status).toBe('sent');
      expect(entry.subject).toBe('Order Confirmation: order-1');
    });

    it('should generate sequential IDs', () => {
      const entry1 = historyService.log(makeNotification());
      const entry2 = historyService.log(makeNotification({ id: 'notif-0002' }));

      expect(entry1.id).toBe('nlog-0001');
      expect(entry2.id).toBe('nlog-0002');
    });

    it('should store error information for failed notifications', () => {
      const notification = makeNotification({
        status: 'failed',
        error: 'Connection refused',
      });
      const entry = historyService.log(notification);

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('Connection refused');
    });

    it('should store metadata', () => {
      const notification = makeNotification({
        metadata: { orderId: 'order-42', userId: 'user-7' },
      });
      const entry = historyService.log(notification);

      expect(entry.metadata).toEqual({ orderId: 'order-42', userId: 'user-7' });
    });

    it('should persist to the repository', () => {
      historyService.log(makeNotification());

      expect(repository.count()).toBe(1);
      const stored = repository.findById('nlog-0001');
      expect(stored).toBeDefined();
      expect(stored?.recipient).toBe('alice@example.com');
    });
  });

  describe('getByRecipient', () => {
    it('should return logs for a specific recipient', () => {
      historyService.log(makeNotification({ recipient: 'alice@example.com' }));
      historyService.log(makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }));
      historyService.log(makeNotification({ id: 'notif-0003', recipient: 'alice@example.com' }));

      const aliceLogs = historyService.getByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(2);
      expect(aliceLogs.every((l) => l.recipient === 'alice@example.com')).toBe(true);

      const bobLogs = historyService.getByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
    });

    it('should return empty array for unknown recipient', () => {
      historyService.log(makeNotification());
      expect(historyService.getByRecipient('nobody@example.com')).toHaveLength(0);
    });
  });

  describe('getByType', () => {
    it('should return logs filtered by type', () => {
      historyService.log(makeNotification({ type: 'order_confirmation' }));
      historyService.log(makeNotification({ id: 'notif-0002', type: 'order_status_update' }));
      historyService.log(makeNotification({ id: 'notif-0003', type: 'order_confirmation' }));

      const confirmations = historyService.getByType('order_confirmation');
      expect(confirmations).toHaveLength(2);

      const updates = historyService.getByType('order_status_update');
      expect(updates).toHaveLength(1);
    });
  });

  describe('getByDateRange', () => {
    it('should return logs within the date range', () => {
      historyService.log(makeNotification({
        sentAt: new Date('2026-01-10T10:00:00Z'),
      }));
      historyService.log(makeNotification({
        id: 'notif-0002',
        sentAt: new Date('2026-01-15T10:00:00Z'),
      }));
      historyService.log(makeNotification({
        id: 'notif-0003',
        sentAt: new Date('2026-01-20T10:00:00Z'),
      }));

      const range = historyService.getByDateRange(
        new Date('2026-01-12T00:00:00Z'),
        new Date('2026-01-18T00:00:00Z'),
      );
      expect(range).toHaveLength(1);
      expect(range[0]?.id).toBe('nlog-0002');
    });

    it('should include boundary dates', () => {
      const exactDate = new Date('2026-01-15T10:00:00Z');
      historyService.log(makeNotification({ sentAt: exactDate }));

      const range = historyService.getByDateRange(exactDate, exactDate);
      expect(range).toHaveLength(1);
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.log(makeNotification({
        recipient: 'alice@example.com',
        type: 'order_confirmation',
        channel: 'email',
        status: 'sent',
        sentAt: new Date('2026-01-15T10:00:00Z'),
      }));
      historyService.log(makeNotification({
        id: 'notif-0002',
        recipient: 'bob@example.com',
        type: 'order_status_update',
        channel: 'webhook',
        status: 'sent',
        sentAt: new Date('2026-01-16T10:00:00Z'),
      }));
      historyService.log(makeNotification({
        id: 'notif-0003',
        recipient: 'alice@example.com',
        type: 'order_status_update',
        channel: 'email',
        status: 'failed',
        error: 'SMTP error',
        sentAt: new Date('2026-01-17T10:00:00Z'),
      }));
    });

    it('should return all logs when no filters are provided', () => {
      expect(historyService.query({})).toHaveLength(3);
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
    });

    it('should filter by type', () => {
      const results = historyService.query({ type: 'order_status_update' });
      expect(results).toHaveLength(2);
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.error).toBe('SMTP error');
    });

    it('should filter by date range', () => {
      const results = historyService.query({
        startDate: new Date('2026-01-16T00:00:00Z'),
        endDate: new Date('2026-01-16T23:59:59Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'order_status_update',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should return empty array when no matches', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        channel: 'webhook',
      });
      expect(results).toHaveLength(0);
    });
  });

  describe('getCount', () => {
    it('should return zero when no logs exist', () => {
      expect(historyService.getCount()).toBe(0);
    });

    it('should return count of all logged notifications', () => {
      historyService.log(makeNotification());
      historyService.log(makeNotification({ id: 'notif-0002' }));
      expect(historyService.getCount()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications when events are dispatched', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      expect(historyService.getCount()).toBe(1);
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.status).toBe('sent');
    });

    it('should log notifications for status change events', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.getCount()).toBe(1);
      const logs = historyService.getByType('order_status_update');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('sent');
    });

    it('should log multiple notifications from multiple events', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      expect(historyService.getCount()).toBe(2);
      expect(historyService.getByType('order_confirmation')).toHaveLength(1);
      expect(historyService.getByType('order_status_update')).toHaveLength(1);
    });

    it('should not log when history service is not set', async () => {
      const freshEventBus = new EventBus();
      const freshNotifService = new NotificationService(freshEventBus);
      // No historyService set

      await freshEventBus.emit(makeOrderCreatedEvent());

      // NotificationService still stores in memory
      expect(freshNotifService.getNotificationCount()).toBe(1);
      // But history service has no logs from this event
      expect(historyService.getCount()).toBe(0);
    });

    it('should capture metadata in history logs', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.query({});
      expect(logs[0]?.metadata).toBeDefined();
      expect(logs[0]?.metadata?.['orderId']).toBe('order-1');
      expect(logs[0]?.metadata?.['userId']).toBe('user-1');
    });
  });
});
